// ProductManager.jsx
import React, { useState } from 'react';
import axios from 'axios';
import './Styles/Global.css';

function ProductManager() {
  const [plant, setPlant] = useState({
    name: '',
    price: '',
    category: '',
    description: '',
    stock: '',
    care: '',
  });
  const [image, setImage] = useState(null);

  const handleChange = (e) => {
    setPlant({ ...plant, [e.target.name]: e.target.value });
  };

  const handleImageChange = (e) => {
    setImage(e.target.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    Object.keys(plant).forEach(key => formData.append(key, plant[key]));
    //console.log(plant);
    if (image) formData.append('image', image);

    try {
      await axios.post('http://localhost:5000/api/admin/products', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
      });
      alert('Plant added!');
    } catch (err) {
      alert('Failed to add plant');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input name="name" onChange={handleChange} placeholder="Plant Name" />
      <input name="price" onChange={handleChange} placeholder="Price" />
      <input name="category" onChange={handleChange} placeholder="Category" />
      <textarea name="description" onChange={handleChange} placeholder="Description" />
      <input name="stock" onChange={handleChange} placeholder="Stock Quantity" />
      <textarea name="care" onChange={handleChange} placeholder="Care Instructions" />
      <input type="file" onChange={handleImageChange} />
      <button type="submit">Add Plant</button>
    </form>
  );
}

export default ProductManager;
